// One-shot generator: collect every `::Tag` reference appearing in
// `:throws` Vecs across core.qlang / error libs, plus the special
// names lifted by error-convert (ParseError, foreign-error names),
// and emit `core/lib/qlang/error/registry.qlang` — a BindStep
// catalog of minimal type-binding declarations
//
//   ::TagName
//     |~~ <auto-generated prose decoded from the name pattern> ~~|
//     {:qlang/kind :type}
//
// Constructors (Quote-impl validators) land in a separate pass per
// the post-redesign plan. This file's purpose is to make every
// referenced tag known to the env so `evalBareTypeKeyword` does
// not raise `TaggedLitTagNotFound` when the same tag appears as
// a TagKeyword carrier in an error-value's `:thrown` field or
// inside an authored `!{:thrown ::Tag ...}` literal.

import { readFileSync, writeFileSync, readdirSync, statSync } from 'node:fs';
import { join } from 'node:path';

const libRoots = [
  'core/lib/qlang/core.qlang',
  'core/lib/qlang/error.qlang',
  'core/lib/qlang/error/observe.qlang',
  'core/lib/qlang/error/guards.qlang'
];

const tagSet = new Set();
for (const path of libRoots) {
  const content = readFileSync(path, 'utf8');
  for (const m of content.matchAll(/::([A-Z][A-Za-z0-9_]*)/g)) {
    tagSet.add(m[1]);
  }
}

// JS-side error class names that surface via error-convert when an
// internal throw site (Projection / parse / host / invariant) fires.
// Some are not listed in any `:throws` Vec because they fire from
// grammar primitives (Projection, ParenGroup) or from the codec /
// effect-laundering / parser / registry rather than from operand
// metadata. Add explicit JS-class enumeration so the registry covers
// every name an error-value can carry on `:thrown`.
const walkDir = (dir, acc = []) => {
  for (const name of readdirSync(dir)) {
    const p = join(dir, name);
    const st = statSync(p);
    if (st.isDirectory()) walkDir(p, acc);
    else if (name.endsWith('.mjs')) acc.push(p);
  }
  return acc;
};
const srcFiles = walkDir('core/src');
for (const file of srcFiles) {
  const content = readFileSync(file, 'utf8');
  // Per-site factory declarations: `declareSubjectError('Foo', …)` etc.
  for (const m of content.matchAll(/declare(?:Subject|Shape|Element|Comparability|Arity|Modifier)Error\(\s*'([A-Z][A-Za-z0-9_]*)'/g)) {
    tagSet.add(m[1]);
  }
  // Direct class declarations: `class Foo extends <Base> {…}` covering
  // every base that error-convert lifts (QlangError hierarchy plus the
  // freestanding `Error` for the peggy-side ParseError).
  for (const m of content.matchAll(/class\s+([A-Z][A-Za-z0-9_]*)\s+extends\s+(?:Qlang[A-Za-z]*Error|ArityError|EffectLaunderingError|Error)\b/g)) {
    const root = m[1];
    // Skip the abstract hierarchy roots — they fingerprint no throw site.
    if (['QlangTypeError', 'EffectLaunderingError', 'QlangInvariantError', 'ArityError', 'QlangError'].includes(root)) continue;
    tagSet.add(root);
  }
}

// Tags that the catalog itself defines as non-error type-bindings —
// keep them out of the registry (they have their own declarations).
const skip = new Set(['conduit', 'qlang', 'json']);
const tags = [...tagSet].filter(t => !skip.has(t.toLowerCase())).sort();

// Decode the prose from the name pattern. Examples:
//   TableSubjectNotVec       → "Subject of `table` is not a Vec."
//   AddRightNotNumber        → "Right operand of `add` is not a Number."
//   AddLeftNotNumber         → "Left operand of `add` is not a Number."
//   SumElementNotNumber      → "Element of `sum` collection is not a Number."
//   GteOperandsNotComparable → "`gte` operands are not pairwise comparable."
//   CondNoBranches           → "`cond` requires at least one branch."
//   ParseError               → "Parser failure — source did not match the grammar."
//
// Falls back to a generic "<name> error" line when no pattern matches.

function pascalToWords(name) {
  return name.replace(/([A-Z])/g, ' $1').trim().split(/\s+/);
}

function describe(tag) {
  // Specific known names with custom prose.
  const custom = {
    ParseError: 'Parser failure — source did not match the grammar.',
    DivisionByZeroError: 'Division by zero in `div`.',
    AxisBindingNotFound: 'Axis-operand could not find a def-step for the requested binding name.',
    EffectLaunderingAtDefParse: '@-effect identifier appears inside a non-@-prefixed def body at parse-time.',
    EffectLaunderingAtCall: '@-effect identifier resolved through env / use / as without an @-prefixed alias at call-time.',
    UnresolvedIdentifierError: 'Identifier lookup failed — no env binding under that name.'
  };
  if (custom[tag]) return custom[tag];

  const words = pascalToWords(tag);
  // Pattern: <Operand><Position>Not<Type>  → "<Position> of `<operand>` is not a <Type>."
  const notIdx = words.indexOf('Not');
  if (notIdx > 0 && notIdx < words.length - 1) {
    const operand = words[0].toLowerCase();
    const positionWords = words.slice(1, notIdx);
    const expectedType = words.slice(notIdx + 1).join(' ');
    const position = positionWords.join(' ').toLowerCase();
    if (position === 'subject') return `Subject of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'left')    return `Left operand of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'right')   return `Right operand of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'element') return `Element of \`${operand}\` collection is not a ${expectedType}.`;
    if (position === 'key')     return `Key argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'pair')    return `Pair argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'count')   return `Count argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'row')     return `Row of \`${operand}\` input is not a ${expectedType}.`;
    if (position === 'index')   return `Index argument of \`${operand}\` is not an ${expectedType}.`;
    if (position === 'prefix')  return `Prefix argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'suffix')  return `Suffix argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'needle')  return `Needle argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'separator') return `Separator argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'name')    return `Name argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'descriptor') return `Descriptor argument of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'params')  return `Parameter list of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'param')   return `Parameter of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'self name') return `Self-name of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'cmp result') return `Comparator result of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'body')    return `Body of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'payload') return `Payload of \`${operand}\` is not a ${expectedType}.`;
    if (position === 'natural') return `\`${operand}\` natural-order subject is not a ${expectedType}.`;
    if (position === 'natural subject') return `\`${operand}\` natural-order subject is not a ${expectedType}.`;
    if (position === 'by key not') return `\`${operand}\` by-key result is not a ${expectedType}.`;
    if (position === 'by key') return `\`${operand}\` by-key subject is not a ${expectedType}.`;
    if (position === 'bare subject') return `\`${operand}\` bare-form subject is not a ${expectedType}.`;
    if (position === 'bare empty') return `\`${operand}\` bare-form received an empty Vec.`;
    if (position === 'pair incompatible') return `\`${operand}\` pair operands have incompatible types.`;
    // Generic fallback for less-common positions.
    return `${positionWords.join(' ')} argument of \`${operand}\` is not a ${expectedType}.`;
  }

  // Pattern: <Operand>NoAlternatives / NoBranches → "<operand> requires at least one ..."
  if (tag.endsWith('NoAlternatives')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` requires at least one alternative.`;
  }
  if (tag.endsWith('NoBranches')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` requires at least one branch.`;
  }
  if (tag.endsWith('OperandsNotComparable')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` operands are not pairwise comparable.`;
  }
  if (tag.endsWith('PairIncompatible')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` pair operands have incompatible container types.`;
  }
  if (tag.endsWith('BareEmpty')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` bare form received an empty Vec.`;
  }
  if (tag.endsWith('ArityInvalid') || tag.endsWith('ArityMismatch') || tag.endsWith('ArityOverflow')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` invocation arity invalid.`;
  }
  if (tag.endsWith('PredArityInvalid')) {
    const op = words[0].toLowerCase();
    return `\`${op}\` predicate-conduit arity invalid for the subject container kind.`;
  }
  if (tag.startsWith('Use')) {
    return `\`use\` encountered a malformed namespace argument or import.`;
  }
  if (tag.startsWith('TaggedLit')) {
    return `\`::tag\` invocation failed — tag is not a registered type binding or its impl is unresolvable.`;
  }
  if (tag.endsWith('SubjectShapeError')) {
    const op = words[0].toLowerCase();
    return `Subject of \`${op}\` does not match the expected shape.`;
  }
  if (tag.startsWith('Def')) {
    return `\`def\` invocation has an invalid name / params / body shape.`;
  }
  return `${tag} — see operand documentation.`;
}

const section = '|~ ──────────────── Named-error type-bindings ──────────────── ~|\n\n';
const decls = tags.map(tag =>
  `::${tag}\n  |~~ ${describe(tag)} ~~|\n  {:qlang/kind :type}`
).join('\n\n');

const banner =
`|~ Catalog of named-error type-bindings — one entry per JS-side
   class declared in core/src/operand-errors.mjs and the
   special error-convert sources (ParseError, foreign-error
   names, axis-operand failures). Each declaration is the
   minimum that makes the tag known to the env so
   \`evalBareTypeKeyword\` finds it and authors can write
   \`!{:thrown ::Tag …}\` literals or \`:add | /throws | first
   | docs\` axis navigations.

   Constructors (Quote-impl validators per §II.3 of the
   redesign plan) land in a later pass. ~|

`;

writeFileSync(
  'core/lib/qlang/error/registry.qlang',
  banner + section + decls + '\n'
);
console.log('wrote core/lib/qlang/error/registry.qlang with', tags.length, 'tags');
